const headers = $json.headers || {};
function pick(name) {
  const variants = [name, name.toLowerCase(), name.toUpperCase()];
  for (const key of variants) {
    if (headers[key] !== undefined && headers[key] !== null && String(headers[key]).trim() !== '') {
      return String(headers[key]).trim();
    }
  }
  return '';
}

const workspaceId = pick('X-Beehive-Workspace-Id');
const runId = pick('X-Beehive-Run-Id');
const stageId = pick('X-Beehive-Stage-Id');
const sourceBucket = pick('X-Beehive-Source-Bucket');
const sourceKey = pick('X-Beehive-Source-Key');
const sourceVersionId = pick('X-Beehive-Source-Version-Id') || null;
const sourceEtag = pick('X-Beehive-Source-Etag') || null;
const manifestPrefix = pick('X-Beehive-Manifest-Prefix') || `beehive-smoke/test_workflow/runs/${runId}/`;

for (const [label, value] of Object.entries({ workspaceId, runId, stageId, sourceBucket, sourceKey })) {
  if (!value) throw new Error(`Missing required Beehive header: ${label}`);
}

const workspacePrefix = manifestPrefix.includes('/runs/')
  ? manifestPrefix.split('/runs/')[0].replace(/\/+$/, '')
  : 'beehive-smoke/test_workflow';
const targetPrefix = `${workspacePrefix}/processed`;

return [{
  json: {
    workspace_id: workspaceId,
    run_id: runId,
    stage_id: stageId,
    source_bucket: sourceBucket,
    source_key: sourceKey,
    source_version_id: sourceVersionId,
    source_etag: sourceEtag,
    manifest_prefix: manifestPrefix,
    workspace_prefix: workspacePrefix,
    target_prefix: targetPrefix,
    save_path: targetPrefix
  }
}];

const pointer = $('Read Beehive headers').first().json;
const source = $json.source_json || $json.json || $json;

const sourceEntityId = source.entity_id || source.tag_id || `smoke_entity_${pointer.run_id}`;
const sourceArtifactId = source.artifact_id || pointer.source_key.split('/').pop().replace(/\.json$/i, '');
const compactRun = pointer.run_id.replace(/[^a-zA-Z0-9]/g, '').slice(0, 16);
const outputArtifactId = `smoke_output_${compactRun}_${sourceArtifactId}`.slice(0, 180);
const outputKey = `${pointer.target_prefix}/${outputArtifactId}.json`;

const canonical = source.canonical_tag_ru || source.raw_article?.canonical_tag_ru || source.tag_id || sourceEntityId;
const output = {
  schema: 'beehive.s3_smoke_output.v1',
  smoke_status: 'ok',
  created_at: new Date().toISOString(),
  beehive_run_id: pointer.run_id,
  source: {
    bucket: pointer.source_bucket,
    key: pointer.source_key,
    version_id: pointer.source_version_id,
    etag: pointer.source_etag,
    entity_id: sourceEntityId,
    artifact_id: sourceArtifactId
  },
  entity_id: sourceEntityId,
  artifact_id: outputArtifactId,
  canonical_tag_ru: canonical,
  entity_type: source.entity_type || source.raw_article?.entity_type || null,
  preview_blocks: source.preview_blocks || []
};

const manifest = {
  schema: 'beehive.s3_artifact_manifest.v1',
  workspace_id: pointer.workspace_id,
  run_id: pointer.run_id,
  source: {
    bucket: pointer.source_bucket,
    key: pointer.source_key,
    version_id: pointer.source_version_id,
    etag: pointer.source_etag
  },
  status: 'success',
  outputs: [
    {
      artifact_id: outputArtifactId,
      entity_id: sourceEntityId,
      relation_to_source: 'same_entity',
      bucket: pointer.source_bucket,
      key: outputKey,
      save_path: pointer.save_path,
      content_type: 'application/json',
      checksum_sha256: null,
      size: Buffer.byteLength(JSON.stringify(output), 'utf8')
    }
  ],
  created_at: new Date().toISOString()
};

const data = await this.helpers.prepareBinaryData(
  Buffer.from(JSON.stringify(output, null, 2), 'utf8'),
  `${outputArtifactId}.json`,
  'application/json'
);

return [{
  json: {
    ...pointer,
    output_bucket: pointer.source_bucket,
    output_key: outputKey,
    output_artifact_id: outputArtifactId,
    output_entity_id: sourceEntityId,
    manifest
  },
  binary: { data }
}];
